        result.append(new_int)
    except ValueError:
        pass
    return result

def process_input_stream(input_data: str) -> list[int]:
    list_data = []
    for line in input_data.strip().split('\n'):
        if line:
            try:
                list_data.append(int(line.strip()))
            except ValueError:
                pass
    return list_data

if __name__ == '__main__':
    initial_data_str = "10\n20\nerror\n30"
